using System;

namespace Windows.UI.Shell.Tasks;

/// <summary>
/// Represents an asset that is generated by an app task.
/// </summary>
public sealed class AppTaskResultAsset
{
	/// <summary>
	/// Creates a new instance of <see cref="AppTaskResultAsset"/>.
	/// </summary>
	/// <param name="name">The name of the generated asset.</param>
	/// <param name="context">A description of the task context.</param>
	/// <param name="iconUri">A path to the icon that represents the task.</param>
	/// <param name="assetUri">The path to the asset generated by the app task.</param>
	public AppTaskResultAsset(string name, string context, Uri iconUri, Uri assetUri)
	{
		Name = name ?? throw new ArgumentNullException(nameof(name));
		Context = context ?? throw new ArgumentNullException(nameof(context));
		IconUri = iconUri ?? throw new ArgumentNullException(nameof(iconUri));
		AssetUri = assetUri ?? throw new ArgumentNullException(nameof(assetUri));
	}

	/// <summary>
	/// Gets the name of the generated asset.
	/// </summary>
	public string Name { get; }

	/// <summary>
	/// Gets the description of the task context.
	/// </summary>
	public string Context { get; }

	/// <summary>
	/// Gets the path to the icon that represents the task.
	/// </summary>
	public Uri IconUri { get; }

	/// <summary>
	/// Gets the path to the asset generated by the app task.
	/// </summary>
	public Uri AssetUri { get; }
}
